<script setup>import{onMounted,reactive,ref}from'vue';import axios from'axios';import PageHeader from'../components/PageHeader.vue';const devices=ref([]),token=ref(''),message=ref(''),form=reactive({name:'Main Gate Face Terminal',type:'facial',location:'Main entrance',provider:'',external_id:''});async function load(){devices.value=(await axios.get('/api/devices')).data}onMounted(load);async function create(){const{data}=await axios.post('/api/devices',form);token.value=data.token;message.value='Device registered. Copy its token now—it is shown only once.';await load()}</script>
<template><PageHeader title="Store devices" subtitle="Register and monitor barcode, POS, and facial-recognition hardware"/><p v-if="message" class="notice">{{message}}</p><div v-if="token" class="secret"><strong>One-time device token</strong><code>{{token}}</code><button class="btn" @click="navigator.clipboard.writeText(token)">Copy token</button></div><div class="two-col"><section class="panel"><div class="panel-head"><h2>Register hardware</h2></div><form class="stack" @submit.prevent="create"><label>Name<input v-model="form.name" required></label><label>Type<select v-model="form.type"><option value="facial">Facial recognition</option><option value="barcode">Barcode scanner</option><option value="pos">POS terminal</option></select></label><label>Location<input v-model="form.location"></label><label>Provider / model<input v-model="form.provider" placeholder="e.g. ZKTeco, Hikvision, Suprema"></label><label>External device ID<input v-model="form.external_id"></label><button class="btn primary">Generate device token</button></form></section><section class="panel"><div class="panel-head"><h2>Connected devices</h2><span class="live">● Monitoring</span></div><div v-for="d in devices" :key="d.id" class="device"><div><strong>{{d.name}}</strong><small>{{d.type}} · {{d.location}}</small></div><span class="tag" :class="{warn:!d.last_seen_at}">{{d.last_seen_at?'Seen '+new Date(d.last_seen_at).toLocaleString():'Never connected'}}</span></div><div v-if="!devices.length" class="empty">No devices registered.</div></section></div><section class="panel guide"><div class="panel-head"><h2>Hardware setup checklist</h2></div><div class="guide-grid"><article><h3>USB barcode scanner</h3><ol><li>Configure the scanner for HID keyboard mode.</li><li>Enable Enter/CR suffix after each scan.</li><li>Set the scanner keyboard layout to match the POS computer.</li><li>Open POS Terminal and scan into the focused barcode field.</li><li>Use EAN-13, UPC, Code 128, or the SKU printed by Nenial.</li></ol></article><article><h3>Facial recognition terminal</h3><ol><li>Use a device/provider that supports HTTPS webhooks.</li><li>Create a Facial device here and copy the one-time bearer token.</li><li>Configure webhook URL: <code>/api/device/attendance</code>.</li><li>Send subject_id, event_id, recognized_at, confidence, and optional status.</li><li>Match each enrolled device subject to the employee Face Subject ID.</li><li>Use HTTPS, restrict outbound IPs, and never send raw biometric templates to Nenial.</li></ol></article></div></section></template>
